namespace sv_a98fdec2d9b14c9bb88a81ed21ab5ff7;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public Theme Theme { get; set; } = Theme.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

using Microsoft.AspNetCore.Components;

namespace sv_a98fdec2d9b14c9bb88a81ed21ab5ff7;

/// <summary>
/// Scoped service that owns the current theme state and pushes updates
/// to both event subscribers and the CascadingValueSource so that
/// [CascadingParameter] consumers (including static-SSR components)
/// re-render automatically.
/// </summary>
public class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _source;
    private ThemeInfo _current;

    public ThemeService(CascadingValueSource<ThemeInfo> source)
    {
        _source = source;
        _current = new ThemeInfo();
    }

    public ThemeInfo Current => _current;

    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        _current.Theme = theme;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string color)
    {
        _current.AccentColor = color;
        await NotifyAsync();
    }

    public async Task UpdateAsync(Theme theme, string accentColor)
    {
        _current.Theme = theme;
        _current.AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        // Push to CascadingValueSource so [CascadingParameter] subscribers update
        await _source.NotifyChangedAsync(_current);
        // Fire event for components that subscribe via OnChange
        OnChange?.Invoke();
    }
}

