﻿@inherits LayoutComponentBase
@inject ThemeService ThemeService
@implements IDisposable

<div class="page" data-theme="@ThemeInfo?.Theme.ToString().ToLower()"
     style="--accent-color: @(ThemeInfo?.AccentColor ?? "#0d6efd")">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <span class="theme-indicator me-3">
                @switch (ThemeInfo?.Theme)
                {
                    case Theme.Dark:
                        <span>🌙 Dark</span>
                        break;
                    case Theme.System:
                        <span>💻 System</span>
                        break;
                    default:
                        <span>☀️ Light</span>
                        break;
                }
                <span class="accent-dot" style="background-color: @(ThemeInfo?.AccentColor ?? "#0d6efd")"></span>
            </span>
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? ThemeInfo { get; set; }

    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        ThemeService.OnChange += _handler;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= _handler;
    }
}

