@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                var isActive = ThemeService.Current.Theme == t;
                <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => SetTheme(t)">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color"
                   class="form-control form-control-color"
                   value="@ThemeService.Current.AccentColor"
                   @onchange="OnAccentChanged" />
            <span>@ThemeService.Current.AccentColor</span>
        </div>

        <h5 class="card-title">Preview</h5>
        <p>
            Current theme: <strong>@ThemeService.Current.Theme</strong><br />
            Accent color:
            <span class="badge" style="background-color: @ThemeService.Current.AccentColor">
                @ThemeService.Current.AccentColor
            </span>
        </p>
    </div>
</div>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        ThemeService.OnChange += _handler;
    }

    private async Task SetTheme(Theme theme)
    {
        await ThemeService.SetThemeAsync(theme);
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString() ?? "#0d6efd";
        await ThemeService.SetAccentColorAsync(color);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= _handler;
    }
}

